class EncryptionManager:
    """Handles encryption/decryption of sensitive data before storing in Redis."""

    def __init__(self, encryption_key: Optional[str] = None):
        key = encryption_key or os.environ.get("REDIS_ENCRYPTION_KEY")
        if not key:
            raise ValueError(
                "Encryption key must be provided via parameter or "
                "REDIS_ENCRYPTION_KEY environment variable"
            )

        # Derive a proper Fernet key from the provided key
        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=32,
            salt=os.environ.get("ENCRYPTION_SALT", "default-salt-change-me").encode(),
            iterations=480000,
        )
        derived_key = base64.urlsafe_b64encode(kdf.derive(key.encode()))
        self._fernet = Fernet(derived_key)

    def encrypt(self, data: str) -> str:
        """Encrypt plaintext data."""
        return self._fernet.encrypt(data.encode()).decode()

    def decrypt(self, encrypted_data: str) -> str:
        """Decrypt encrypted data."""
        return self._fernet.decrypt(encrypted_data.encode()).decode()


class RedisConnectionManager:
    """Manages secure connections to Redis cluster/sentinel."""

    def __init__(self):
        self._connection_pool = None
        self._sentinel = None
