        """Load Redis configuration from environment variables only."""
        config = {
            "host": os.environ.get("REDIS_HOST", "localhost"),
            "port": int(os.environ.get("REDIS_PORT", "6379")),
            "db": int(os.environ.get("REDIS_DB", "0")),
            "password": os.environ.get("REDIS_PASSWORD"),
            "username": os.environ.get("REDIS_USERNAME"),
            "ssl": os.environ.get("REDIS_SSL", "true").lower() == "true",
            "ssl_cert_reqs": os.environ.get("REDIS_SSL_CERT_REQS", "required"),
            "ssl_ca_certs": os.environ.get("REDIS_SSL_CA_CERTS"),
            "ssl_certfile": os.environ.get("REDIS_SSL_CERTFILE"),
            "ssl_keyfile": os.environ.get("REDIS_SSL_KEYFILE"),
            "socket_timeout": int(os.environ.get("REDIS_SOCKET_TIMEOUT", "5")),
            "socket_connect_timeout": int(
                os.environ.get("REDIS_CONNECT_TIMEOUT", "5")
            ),
            "retry_on_timeout": True,
            "decode_responses": True,
            "max_connections": int(os.environ.get("REDIS_MAX_CONNECTIONS", "20")),
        }

