    @retry_on_failure(max_retries=3)
    def check_rate_limit(
        self,
        identifier: str,
        max_requests: int = 100,
        window_seconds: int = 60,
    ) -> Dict[str, Any]:
        """
        Check rate limit using sliding window counter.

        Args:
            identifier: The identifier to rate limit (e.g., user_id, IP)
            max_requests: Maximum requests allowed in the window
            window_seconds: Time window in seconds

        Returns:
            Dict with 'allowed', 'remaining', 'reset_at' keys
        """
        if not identifier:
            raise ValueError("identifier is required")

        key = self._hash_key(self.PREFIX_RATE_LIMIT, identifier)
        client = self._get_client()

        pipe = client.pipeline(transaction=True)
        try:
            current_count = client.get(key)
            if current_count is None:
                pipe.setex(key, window_seconds, 1)
                pipe.execute()
                return {
                    "allowed": True,
                    "remaining": max_requests - 1,
                    "reset_at": time.time() + window_seconds,
                }

            current_count = int(current_count)
            if current_count >= max_requests:
                ttl = client.ttl(key)
                return {
                    "allowed": False,
                    "remaining": 0,
                    "reset_at": time.time() + max(ttl, 0),
                }

            pipe.incr(key)
            pipe.execute()
            remaining = max_requests - current_count - 1
            ttl = client.ttl(key)
            return {
                "allowed": True,
                "remaining": max(remaining, 0),
                "reset_at": time.time() + max(ttl, 0),
            }
        except RedisError:
            pipe.reset()
            raise

