def create_app():
    """Create a Flask application with the cache service."""
    try:
        from flask import Flask, jsonify, request, g
    except ImportError:
        logger.error("Flask is not installed. Install with: pip install flask")
        return None

    app = Flask(__name__)

    # Initialize services
    cache_service = SecureCacheService()

    @app.before_request
    def before_request():
        g.cache_service = cache_service

    @app.teardown_appcontext
    def teardown(exception):
        pass

    @app.route("/health", methods=["GET"])
    def health():
        result = cache_service.health_check()
        status_code = 200 if result["status"] == "healthy" else 503
        return jsonify(result), status_code

    @app.route("/session", methods=["POST"])
    def create_session():
        data = request.get_json()
        if not data or "user_id" not in data:
            return jsonify({"error": "user_id is required"}), 400

        user_id = str(data["user_id"])
        session_token = secrets.token_urlsafe(32)

        metadata = {}
        if request.remote_addr:
            metadata["ip_address"] = request.remote_addr
        if request.user_agent.string:
            metadata["user_agent"] = request.user_agent.string[:256]

        try:
            cache_service.store_session_token(
                user_id=user_id,
                session_token=session_token,
                metadata=metadata,
            )
            return jsonify({
                "session_token": session_token,
                "expires_in": SecureCacheService.SESSION_TOKEN_TTL,
            }), 201
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/session/<user_id>", methods=["GET"])
    def get_session(user_id):
        try:
            session_data = cache_service.get_session_token(user_id)
            if session_data is None:
                return jsonify({"error": "Session not found or expired"}), 404
            return jsonify(session_data), 200
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/session/<user_id>", methods=["DELETE"])
    def delete_session(user_id):
        try:
            result = cache_service.invalidate_session(user_id)
            if result:
                return jsonify({"message": "Session invalidated"}), 200
            return jsonify({"message": "Session not found"}), 404
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/api-key", methods=["POST"])
    def store_api_key():
        data = request.get_json()
        if not data or "user_id" not in data or "api_key" not in data:
            return jsonify({"error": "user_id and api_key are required"}), 400

        try:
            cache_service.store_api_key(
                user_id=str(data["user_id"]),
                api_key=str(data["api_key"]),
                scopes=data.get("scopes", []),
            )
            return jsonify({
                "message": "API key stored",
                "expires_in": SecureCacheService.API_KEY_TTL,
            }), 201
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/api-key/validate", methods=["POST"])
    def validate_api_key():
        data = request.get_json()
        if not data or "api_key" not in data:
            return jsonify({"error": "api_key is required"}), 400

        try:
            result = cache_service.validate_api_key(str(data["api_key"]))
            if result is None:
                return jsonify({"valid": False}), 401
            return jsonify({"valid": True, "data": result}), 200
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/rate-limit/check", methods=["POST"])
    def check_rate_limit():
        data = request.get_json()
        if not data or "identifier" not in data:
            return jsonify({"error": "identifier is required"}), 400

        try:
            result = cache_service.check_rate_limit(
                identifier=str(data["identifier"]),
                max_requests=data.get("max_requests", 100),
                window_seconds=data.get("window_seconds", 60),
            )
            status_code = 200 if result["allowed"] else 429
            return jsonify(result), status_code
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    @app.route("/user/<user_id>/invalidate-all", methods=["POST"])
    def invalidate_all(user_id):
        try:
            deleted = cache_service.invalidate_all_user_data(user_id)
            return jsonify({
                "message": f"Invalidated {deleted} cache entries",
                "deleted_count": deleted,
            }), 200
        except RedisError:
            return jsonify({"error": "Service unavailable"}), 503

    return app


if __name__ == "__main__":
    # Verify required environment variables
    required_vars = ["REDIS_PASSWORD", "REDIS_ENCRYPTION_KEY"]
    missing = [var for var in required_vars if not os.environ.get(var)]
    if missing:
        logger.error(
            "Missing required environment variables: %s", ", ".join(missing)
        )
        logger.info("Required environment variables:")
        logger.info("  REDIS_HOST - Redis host (default: localhost)")
        logger.info("  REDIS_PORT - Redis port (default: 6379)")
        logger.info("  REDIS_PASSWORD - Redis password (required)")
        logger.info("  REDIS_ENCRYPTION_KEY - Key for encrypting data at rest (required)")
        logger.info("  REDIS_KEY_HMAC_SECRET - HMAC secret for key hashing")
        logger.info("  ENCRYPTION_SALT - Salt for key derivation")
        logger.info("  REDIS_SSL - Enable SSL (default: true)")
        logger.info("  REDIS_USE_CLUSTER - Use Redis Cluster mode (default: false)")
        logger.info("  REDIS_USE_SENTINEL - Use Redis Sentinel (default: false)")
        exit(1)

    app = create_app()
    if app:
        # Run with secure defaults - bind to localhost only
        app.run(
            host=os.environ.get("SERVICE_HOST", "127.0.0.1"),
            port=int(os.environ.get("SERVICE_PORT", "8080")),
            debug=False,  # Never enable debug in production
        )